/**
 * Compose first-party BlockEditor plugins for host apps.
 *
 * @module BlockEditor/plugins/build-plugins
 */

/**
 * @typedef {object} BlockEditorPluginOptions
 * @property {(payload: object) => Promise<{ mode?: string, text?: string, message?: string, blocks?: Array<object> }|null>} [askAI]
 * @property {boolean} [markdownShortcuts]
 * @property {boolean} [aiSkills]
 * @property {object} [aiSurfaces]
 * @property {Array<object>} [aiSkillsList]
 * @property {Array<object|Function>} [extra]
 */

/**
 * Build plugin list for {@code new BlockEditor(el, { plugins })}.
 *
 * @param {typeof import('../index.js').default} BlockEditor
 * @param {BlockEditorPluginOptions} [options]
 * @returns {Array<object|Function>}
 */
export function buildBlockEditorPlugins(BlockEditor, options = {}) {
    /** @type {Array<object|Function>} */
    const plugins = [];

    if (options.markdownShortcuts !== false) {
        const factory = BlockEditor?.plugins?.markdownShortcuts;
        if (typeof factory === 'function') {
            plugins.push(factory());
        }
    }

    const wantAi = options.aiSkills !== false && typeof options.askAI === 'function';
    const aiFactory = BlockEditor?.plugins?.aiSkills;
    if (wantAi && typeof aiFactory === 'function') {
        plugins.push(
            aiFactory({
                askAI: options.askAI,
                surfaces: options.aiSurfaces ?? { formatBar: true, slash: true, blockMenu: true },
                skills: options.aiSkillsList,
            }),
        );
    }

    if (Array.isArray(options.extra)) {
        plugins.push(...options.extra);
    }

    return plugins;
}

export default buildBlockEditorPlugins;
