/**
 * Notion-style markdown triggers on Space at block start.
 *
 * @module BlockEditor/plugins/markdown-shortcuts
 */

const RULES = Object.freeze([
    { re: /^###$/, type: 'heading', meta: { level: 3 } },
    { re: /^##$/, type: 'heading', meta: { level: 2 } },
    { re: /^#$/, type: 'heading', meta: { level: 1 } },
    { re: /^[-*]$/, type: 'bulleted-list', meta: {} },
    { re: /^1\.$/, type: 'numbered-list', meta: {} },
    { re: /^\[\s?\]$/, type: 'todo', meta: { checked: false } },
    { re: /^>$/, type: 'quote', meta: {} },
    { re: /^---$/, type: 'divider', meta: {} },
]);

/**
 * @param {string} html
 */
function plainTextFromHtml(html) {
    const el = document.createElement('div');
    el.innerHTML = String(html || '');
    return (el.textContent || '').trim();
}

/** @returns {{ name: string, init: (ctx: object) => (() => void)|void }} */
export function createMarkdownShortcutsPlugin() {
    return {
        name: 'markdown-shortcuts',
        init(ctx) {
            const root = ctx.container;
            if (!(root instanceof HTMLElement)) return;

            /** @param {InputEvent} ev */
            const onBeforeInput = (ev) => {
                if (ev.inputType !== 'insertText' || ev.data !== ' ') return;
                const blockId = ctx.getActiveBlockId?.();
                if (!blockId) return;
                const block = ctx.getBlock?.(blockId);
                if (!block || block.type !== 'paragraph') return;

                const text = plainTextFromHtml(block.content);
                for (const rule of RULES) {
                    if (!rule.re.test(text)) continue;
                    ev.preventDefault();
                    ctx.convertBlock?.(blockId, rule.type, rule.meta);
                    if (rule.type !== 'divider') {
                        ctx.updateBlock?.(blockId, { content: '' });
                    }
                    return;
                }
            };

            root.addEventListener('beforeinput', onBeforeInput, true);
            return () => root.removeEventListener('beforeinput', onBeforeInput, true);
        },
    };
}

export default createMarkdownShortcutsPlugin;
