// ═══════════════════════════════════════════════════════════════════
// Notion-inspired JIT styling.
//
// The layout mirrors Notion's page surface: a ~720–780px column
// centred on the page, 16px body text with 1.5 line-height, tight
// inter-block spacing, and a hover-reveal row of controls to the
// left of each block. Colours resolve via ``--be-*`` tokens defined
// in BlockEditor.def.js → the host theme (light/dark) just works.
//
// Keep the PART.*.jit strings authoritative — ``BlockEditor.css`` is
// only a fallback for consumers that don't run the JIT pipeline.
// ═══════════════════════════════════════════════════════════════════

// ROOT font-size inherits from the host by default via ``--be-font-size``
// (see BlockEditor.def.js). Headings and spacing below use ``em`` so they
// scale proportionally with whatever body size the host resolves to.
PART.ROOT.jit     = 'relative [max-width:var(--be-max-width)] [margin:0_auto] [padding:var(--be-padding)] [font-family:var(--be-font-stack)] [font-size:var(--be-font-size)] [line-height:var(--be-line-height)] fg-[var(--be-text)] bg-[var(--be-bg)] [min-height:var(--be-min-height)] [--be-ctrl-w:44px] [--be-row-indent:calc(var(--be-ctrl-w)_+_6px)] [&_.block-wrapper:hover]:bg-[var(--be-row-hover)] [&_.block-wrapper:hover_.block-controls]:[opacity:1]';
// Left-indent math must match the block-content column so the title, every
// paragraph, and headings all share the same left edge:
//   wrapper padding-left (2) + controls width (44) + gap (2) + block-content
//   padding-left (2) = 50px  ≈  `--be-ctrl-w + 6px`.
PART.TITLE.jit    = 'text-[var(--be-title-font-size)] fw-[var(--be-title-font-weight)] [line-height:var(--be-title-line-height)] [letter-spacing:-0.02em] [margin:0_0_var(--be-space-md)] [padding:3px_0_3px_var(--be-row-indent)] [border:none] [outline:none] fg-[var(--be-text)] w-full [word-break:break-word]';
PART.CONTENT.jit  = 'relative';
PART.WRAPPER.jit  = 'relative flex items-start gap-[2px] [padding:3px_2px] rounded-[3px] [transition:background_120ms_ease] {is-dragging}:[opacity:0.4] {is-dragging}:pointer-events-none';
// ``user-select:none`` is critical for cross-block drag selection — without
// it, dragging from block A's text through block B's controls column into
// block B's text snaps the selection shut at the controls boundary (the
// browser treats the handle/add buttons as a selection sink). Notion uses
// the same trick for its row-left gutter.
PART.CONTROLS.jit = 'flex items-center gap-[0px] w-[var(--be-ctrl-w)] [opacity:0] [transition:opacity_140ms_ease] shrink-0 [padding-top:2px] [user-select:none]';
PART.BLOCK_CONTENT.jit = 'flex-1 min-w-0 [line-height:1.5] [padding:3px_2px] [word-break:break-word] [caret-color:var(--be-text)]';
// Floating selection pill — dark background, small buttons, subtle shadow.
//
// IMPORTANT: don't use ``hidden`` (display:none) + ``{is-visible}:flex`` — the
// compiled rules have the same specificity and ``display:none`` wins depending
// on JIT emit order, which is exactly why the format bar never appeared in
// some builds. Instead we always render as flex and toggle ``opacity`` /
// ``pointer-events`` — same pattern Dropdown.MENU uses — so the show/hide
// also animates cleanly.
PART.FORMAT_BAR.jit = 'absolute flex items-stretch [gap:0] [padding:2px] [background:var(--be-fmtbar-bg)] rounded-[6px] [box-shadow:var(--be-fmtbar-shadow)] [z-index:100] [transform:translateX(-50%)] [pointer-events:none] [opacity:0] [transition:opacity_120ms_ease] [font-size:14px] [top:-9999px] [left:-9999px] {is-visible}:[pointer-events:auto] {is-visible}:[opacity:1]';
PART.SLASH_MENU.jit = 'absolute flex flex-col [width:320px] [max-height:360px] [overflow-y:auto] bg-[var(--be-bg-raised)] [border:1px_solid_var(--be-border)] rounded-[8px] [box-shadow:var(--be-menu-shadow)] [z-index:110] [padding:6px_0] [font-size:14px] [top:-9999px] [left:-9999px] [opacity:0] [pointer-events:none] [transition:opacity_120ms_ease] {is-visible}:[opacity:1] {is-visible}:[pointer-events:auto]';
PART.HEADING.jit  = 'fw-600 fg-[var(--be-text)] [border:none] [outline:none] [word-break:break-word] [margin:0] [line-height:1.3] [letter-spacing:-0.01em]';
PART.ADD_BTN.jit  = 'w-[22px] h-[22px] flex items-center justify-center [border:none] bg-transparent [padding:0] rounded-[4px] cursor-pointer fg-[var(--be-text-faint)] text-[18px] leading-none [transition:background_100ms,color_100ms] hover:bg-[var(--be-bg-hover)] hover:fg-[var(--be-text-secondary)]';
PART.HANDLE.jit   = 'w-[22px] h-[22px] flex items-center justify-center [border:none] bg-transparent [padding:0] rounded-[4px] cursor-grab active:cursor-grabbing fg-[var(--be-text-faint)] text-[16px] leading-none [transition:background_100ms,color_100ms] hover:bg-[var(--be-bg-hover)] hover:fg-[var(--be-text-secondary)]';
PART.LIST_ROW.jit = 'flex items-baseline gap-[8px]';
PART.LIST_MARKER.jit = 'shrink-0 select-none fg-[var(--be-text-secondary)] [min-width:18px] [text-align:right]';
PART.LIST_CONTENT.jit = 'flex-1 min-w-0';
PART.TODO_ROW.jit = 'flex items-start gap-[8px]';
PART.TODO_CHECK.jit = 'shrink-0 [margin-top:5px] [accent-color:var(--be-accent)]';
PART.TODO_CONTENT.jit = 'flex-1 min-w-0';
PART.FORMAT_BTN.jit = 'inline-flex items-center justify-center [min-width:30px] h-[30px] [padding:0_8px] [border:none] bg-transparent rounded-[4px] cursor-pointer fg-[var(--be-fmtbar-fg)] text-[14px] leading-none [transition:background_100ms] hover:[background:var(--be-fmtbar-fg-hover-bg)] focus-visible:[outline:2px_solid_var(--be-accent)] focus-visible:[outline-offset:-1px]';
PART.DRAG_INDICATOR.jit = 'hidden absolute [left:0] [right:0] h-[2px] bg-[var(--be-accent)] rounded-[1px] [z-index:50] pointer-events-none [box-shadow:0_0_0_1px_var(--be-accent)] before:content-empty before:absolute before:[top:50%] before:[transform:translateY(-50%)] before:w-[6px] before:h-[6px] before:rounded-full before:bg-[var(--be-accent)] before:[left:0] after:content-empty after:absolute after:[top:50%] after:[transform:translateY(-50%)] after:w-[6px] after:h-[6px] after:rounded-full after:bg-[var(--be-accent)] after:[right:0]';
PART.SLASH_ITEM.jit = 'flex items-center gap-[10px] [padding:6px_12px] [margin:0_4px] rounded-[4px] cursor-pointer [transition:background_80ms] hover:bg-[var(--be-bg-hover)] {is-active}:bg-[var(--be-bg-hover)]';
PART.SLASH_ICON.jit = 'w-[36px] h-[36px] flex items-center justify-center rounded-[4px] bg-[var(--be-bg-inset)] [border:1px_solid_var(--be-border)] text-[15px] shrink-0 fg-[var(--be-text-secondary)]';
PART.SLASH_INFO.jit = 'flex flex-col min-w-0';
PART.SLASH_LABEL.jit = 'text-[14px] fw-500 fg-[var(--be-text)] leading-[1.3]';
PART.SLASH_DESC.jit = 'text-[12px] fg-[var(--be-text-muted)] leading-[1.3] [white-space:nowrap] [overflow:hidden] [text-overflow:ellipsis]';
// Headings scale with the editor's resolved body size (em, not rem), so
// a 14px host body yields 14*1.875=26.25px H1, a 16px host 30px, etc.
PART.HEADING_H1.jit = 'text-[1.875em] [margin-top:var(--be-space-2xl)]';
PART.HEADING_H2.jit = 'text-[1.5em] [margin-top:var(--be-space-xl)]';
PART.HEADING_H3.jit = 'text-[1.25em] [margin-top:var(--be-space-lg)]';
PART.HEADING_H4.jit = 'text-[1.125em] [margin-top:var(--be-space-md)]';