/**
 * @fileoverview BlockEditor view — DOM construction for toolbar, block
 *               container, individual block rendering (all types), drag
 *               handles, inline formatting bar, and slash command menu.
 *
 * @module module/BlockEditor/view
 */

import { customBlockTypes, PART } from './constants.js';
import Icons from '../Icons.js';
import { getMarkdownEditor } from './helpers.js';
import { bindEditableEvents } from './events.js';
import razyui from '../../index.js';

// ═══════════════════════════════════════════════
// Block wrapper
// ═══════════════════════════════════════════════

/**
 * Render a block wrapper with side controls (add button, drag handle)
 * and the block's content area.
 * @param {Object} ctx   — editor context
 * @param {Object} block — block data
 * @returns {HTMLElement}
 */
export function renderBlockWrapper(ctx, block) {
    const wrapper = PART.WRAPPER.create({ 'data-block-id': block.id, 'data-block-type': block.type });

    // ── Side controls ──
    const controls = PART.CONTROLS.create();

    // Add button
    const addBtn = PART.ADD_BTN.create({ type: 'button', innerHTML: '+', title: 'Add block below' });
    controls.append(addBtn);

    // Drag handle
    const handle = PART.HANDLE.create({ type: 'button', innerHTML: '\u2807', title: 'Drag to reorder / Click for options', draggable: false });
    controls.append(handle);

    wrapper.append(controls);

    // ── Content ──
    const content = renderBlockContent(ctx, block);
    wrapper.append(content);

    return wrapper;
}

// ═══════════════════════════════════════════════
// Block content (per-type rendering)
// ═══════════════════════════════════════════════

/**
 * Render the content area for a block based on its type.
 * @param {Object} ctx
 * @param {Object} block
 * @returns {HTMLElement}
 */
export function renderBlockContent(ctx, block) {
    const container = PART.BLOCK_CONTENT.create();

    switch (block.type) {
        case 'paragraph':
            container.append(createEditable(ctx, block, 'div', 'block-text'));
            break;

        case 'regular':
            createLiteMarkdownBlock(ctx, block).then(el => container.append(el));
            break;

        case 'heading': {
            const tag = `h${block.meta.level || 1}`;
            const headingPartMap = { 1: PART.HEADING_H1, 2: PART.HEADING_H2, 3: PART.HEADING_H3, 4: PART.HEADING_H4 };
            const el = razyui.el(tag, { className: 'block-heading', contentEditable: 'true', 'data-placeholder': `Heading ${block.meta.level || 1}`, innerHTML: block.content });
            PART.HEADING.apply(el);
            (headingPartMap[block.meta.level] || PART.HEADING_H1).apply(el);
            bindEditableEvents(ctx, el, block);
            container.append(el);
            break;
        }

        case 'bulleted-list': {
            const row = PART.LIST_ROW.create();
            const marker = PART.LIST_MARKER.create({ textContent: '\u2022' });
            const listContent = createEditable(ctx, block, 'div', 'block-list-content');
            PART.LIST_CONTENT.apply(listContent);
            row.append(marker).append(listContent);
            container.append(row);
            break;
        }

        case 'numbered-list': {
            const row = PART.LIST_ROW.create();
            const marker = PART.LIST_MARKER.create().addClass('block-list-number');
            // Calculate number based on consecutive numbered-list blocks above
            const idx = ctx.blocks.findIndex(b => b.id === block.id);
            let num = 1;
            for (let i = idx - 1; i >= 0; i--) {
                if (ctx.blocks[i].type !== 'numbered-list') break;
                num++;
            }
            marker.text(`${num}.`);
            const numListContent = createEditable(ctx, block, 'div', 'block-list-content');
            PART.LIST_CONTENT.apply(numListContent);
            row.append(marker).append(numListContent);
            container.append(row);
            break;
        }

        case 'todo': {
            const row = PART.TODO_ROW.create();
            const checkbox = PART.TODO_CHECK.create({ type: 'checkbox', checked: !!block.meta.checked });
            row.append(checkbox);
            const ed = createEditable(ctx, block, 'div', 'block-todo-content');
            PART.TODO_CONTENT.apply(ed);
            row.append(ed);
            if (block.meta.checked) row.addClass('is-checked');
            container.append(row);
            break;
        }

        case 'code': {
            const codeWrap = razyui.el('div', { className: 'block-code-wrap' });

            const langInput = razyui.el('input', { type: 'text', className: 'block-code-lang', placeholder: 'language', value: block.meta.language || '' });
            codeWrap.append(langInput);

            const pre = razyui.el('pre');
            const code = razyui.el('code', { className: 'block-code', contentEditable: 'true', spellcheck: false, textContent: block.content });
            pre.append(code);
            codeWrap.append(pre);
            container.append(codeWrap);
            break;
        }

        case 'quote': {
            const bq = razyui.el('blockquote', { className: 'block-quote' });
            const ed = createEditable(ctx, block, 'div', 'block-quote-text');
            bq.append(ed);
            container.append(bq);
            break;
        }

        case 'divider':
            container.html('<hr class="block-divider">');
            break;

        case 'callout': {
            const callout = razyui.el('div', { className: 'block-callout' });
            const emojiBtn = razyui.el('span', { className: 'block-callout-icon', textContent: block.meta.emoji || '\uD83D\uDCA1', title: 'Click to change emoji' });
            callout.append(emojiBtn)
                   .append(createEditable(ctx, block, 'div', 'block-callout-text'));
            container.append(callout);
            break;
        }

        case 'toggle': {
            const details = razyui.el('details', { className: 'block-toggle' });
            if (block.meta.open) details[0].open = true;
            const summary = razyui.el('summary', { className: 'block-toggle-summary', contentEditable: 'true', innerHTML: block.meta.summary || 'Toggle', 'data-placeholder': 'Toggle heading' });
            details.append(summary);
            const inner = createEditable(ctx, block, 'div', 'block-toggle-content');
            details.append(inner)
                   .on('toggle', () => {
                block.meta.open = details[0].open;
            });
            container.append(details);
            break;
        }

        case 'image': {
            const imgWrap = razyui.el('div', { className: 'block-image-wrap' });

            if (block.meta.url) {
                const img = razyui.el('img', { className: 'block-image', src: block.meta.url, alt: block.meta.alt || '' });
                imgWrap.append(img);
            } else {
                const prompt = razyui.el('div', { className: 'block-image-prompt', innerHTML: '<span>' + Icons.svg('image', { size: 16, strokeWidth: 1.5 }) + '</span> Add an image URL' });
                imgWrap.append(prompt);
            }
            container.append(imgWrap);
            break;
        }

        default: {
            // Check custom block type plugins
            const customType = customBlockTypes.get(block.type);
            if (customType && typeof customType.render === 'function') {
                const api = {
                    fireChange: () => ctx.fireChange(),
                    getEditableInBlock: (id) => ctx.getEditableInBlock(id),
                    focusBlock: (id, pos) => ctx.focusBlock(id, pos),
                    addBlock: (type, afterId, content, meta) => ctx.addBlock(type, afterId, content, meta),
                    removeBlock: (id) => ctx.removeBlock(id),
                };
                customType.render(block, container[0], api);
            } else {
                container.append(createEditable(ctx, block, 'div', 'block-text'));
            }
        }
    }

    return container;
}

// ═══════════════════════════════════════════════
// Contenteditable factory
// ═══════════════════════════════════════════════

/**
 * Create a contenteditable element for a block, with events auto-bound.
 * @param {Object} ctx
 * @param {Object} block
 * @param {string} tag       — element tag name (e.g. 'div')
 * @param {string} className — CSS class
 * @returns {HTMLElement}
 */
export function createEditable(ctx, block, tag, className) {
    const el = razyui.el(tag, { className, contentEditable: 'true', innerHTML: block.content });

    if (!block.content) {
        const idx = ctx.blocks.indexOf(block);
        if (idx === 0 && ctx.config.placeholder) {
            el.attr('data-placeholder', ctx.config.placeholder);
        } else {
            el.attr('data-placeholder', 'Type \'/\' for commands\u2026');
        }
    }

    bindEditableEvents(ctx, el, block);
    return el;
}

// ═══════════════════════════════════════════════
// Lite MarkdownEditor block
// ═══════════════════════════════════════════════

/**
 * Create a lite MarkdownEditor instance for a "regular" block.
 * @param {Object} ctx
 * @param {Object} block
 * @returns {Promise<HTMLElement>}
 */
export async function createLiteMarkdownBlock(ctx, block) {
    const wrap = razyui.el('div', { className: 'block-lite-md' });

    const MarkdownEditor = await getMarkdownEditor();
    const mdEditor = new MarkdownEditor(wrap[0], {
        lite: true,
        value: block.content || '',
        placeholder: ctx.blocks.indexOf(block) === 0 && ctx.config.placeholder
            ? ctx.config.placeholder
            : 'Type markdown here\u2026',
        onChange: (md) => {
            block.content = md;
            ctx.fireChange();
        },
    });

    ctx.liteEditors.set(block.id, mdEditor);

    return wrap;
}

// ═══════════════════════════════════════════════
// Format bar (floating inline formatting toolbar)
// ═══════════════════════════════════════════════

/**
 * Build the floating inline formatting toolbar element.
 *
 * Buttons come from the plugin-host's `formatButtons` registry; the built-in
 * plugin seeds B / I / S / <> / link. Re-rendering is driven by the plugin
 * host's registry-change subscription so new plugin buttons show up live.
 *
 * @param {Object} ctx
 * @returns {HTMLElement}
 */
export function buildFormatBar(ctx) {
    const bar = PART.FORMAT_BAR.create();
    bar[0].setAttribute('role', 'toolbar');

    const render = () => {
        bar[0].innerHTML = '';
        const buttons = ctx.plugins?.formatButtons || [];
        buttons.forEach(b => {
            const icon = (b.icon && typeof b.icon === 'string') ? b.icon : null;
            const label = b.label != null ? b.label : (icon || '?');
            const btn = PART.FORMAT_BTN.create({
                type: 'button',
                innerHTML: icon || label,
                title: b.title || b.label || '',
                'data-btn-id': b.id,
                'data-cmd': b.cmd || '',
            });
            if (b.style) btn.attr('style', b.style);
            if (b.ariaLabel) btn.attr('aria-label', b.ariaLabel);
            bar.append(btn);
        });
    };

    render();
    if (ctx.plugins?.onRegistryChange) {
        ctx.plugins.onRegistryChange('format', render);
    }
    // Also expose the renderer so events.js can refresh button active state on selectionchange.
    bar._renderFormatBar = render;
    return bar;
}

// ═══════════════════════════════════════════════
// Slash command menu
// ═══════════════════════════════════════════════

/**
 * Build the slash command popup menu DOM element.
 *
 * Items come from `ctx.plugins.slashCommands` which is seeded by the
 * plugin-host with BLOCK_TYPES + legacy customCommands/customBlockTypes,
 * plus anything plugins have `registerSlashCommand`'d. Items are grouped
 * by the optional `group` field; groups render in first-seen order.
 *
 * @param {Object} ctx
 * @returns {HTMLElement}
 */
export function buildSlashMenu(ctx) {
    const menu = PART.SLASH_MENU.create();
    menu[0].setAttribute('role', 'menu');

    const render = () => {
        menu[0].innerHTML = '';

        const source = (ctx.plugins?.slashCommands || []).slice();
        // Back-compat with legacy renderer that expects `ctx.slashAllItems`
        ctx.slashAllItems = source;

        // Group by `group` (preserve first-seen order)
        const groupOrder = [];
        const byGroup   = new Map();
        source.forEach((item, i) => {
            const g = item.group || 'Basic';
            if (!byGroup.has(g)) { byGroup.set(g, []); groupOrder.push(g); }
            byGroup.get(g).push({ ...item, _flatIndex: i });
        });

        let itemCount = 0;
        groupOrder.forEach((g, gi) => {
            if (gi > 0 || groupOrder.length > 1) {
                const header = razyui.el('div', {
                    className: 'block-slash-group',
                    textContent: g,
                });
                header.attr('style', 'padding:6px 12px 2px;font-size:0.68rem;font-weight:600;letter-spacing:0.04em;text-transform:uppercase;color:var(--be-text-muted);');
                menu.append(header);
            }
            byGroup.get(g).forEach(bt => {
                const item = PART.SLASH_ITEM.create({
                    'data-index': bt._flatIndex,
                    role: 'menuitem',
                });

                const icon  = PART.SLASH_ICON.create({ innerHTML: bt.icon || '\u2756' });
                const info  = PART.SLASH_INFO.create();
                const label = PART.SLASH_LABEL.create({ textContent: bt.label });
                const desc  = PART.SLASH_DESC.create({ textContent: bt.desc || '' });

                info.append(label).append(desc);
                item.append(icon).append(info);
                menu.append(item);
                itemCount++;
            });
        });

        if (itemCount === 0) {
            const empty = razyui.el('div', { textContent: 'No matches' });
            empty.attr('style', 'padding:12px;color:var(--be-text-muted);text-align:center;font-size:0.85rem;');
            menu.append(empty);
        }
    };

    render();
    if (ctx.plugins?.onRegistryChange) {
        ctx.plugins.onRegistryChange('slash', render);
    }
    menu._renderSlashMenu = render;

    return menu;
}

// ═══════════════════════════════════════════════
// Block menu (drag-handle click menu: Turn into / Duplicate / …)
// ═══════════════════════════════════════════════

/**
 * Build the per-block action menu (opened by clicking the drag handle).
 * Items come from `ctx.plugins.blockMenuItems` plus the built-in defaults
 * seeded by the built-in plugin.
 *
 * @param {Object} ctx
 * @param {string} blockId — target block id (for `when()` filters)
 * @returns {HTMLElement}
 */
export function buildBlockMenu(ctx, blockId) {
    const menu = razyui.el('div', { className: 'block-handle-menu' });
    menu.attr('role', 'menu');
    menu.attr('style', [
        'position:absolute',
        'background:var(--be-bg)',
        'border:1px solid var(--be-border)',
        'border-radius:var(--be-radius)',
        'box-shadow:var(--be-shadow-lg)',
        'padding:4px 0',
        'min-width:200px',
        'max-height:360px',
        'overflow-y:auto',
        'z-index:125',
        'font-size:0.875rem',
    ].join(';'));

    const items = (ctx.plugins?.blockMenuItems || []).filter(it => {
        if (it.separator) return true;
        if (typeof it.when === 'function') {
            try { return !!it.when(blockId); } catch (_) { return false; }
        }
        return true;
    });

    // Group like the slash menu
    const groupOrder = [];
    const byGroup   = new Map();
    items.forEach(it => {
        const g = it.group || '';
        if (!byGroup.has(g)) { byGroup.set(g, []); groupOrder.push(g); }
        byGroup.get(g).push(it);
    });

    groupOrder.forEach((g, gi) => {
        if (g && (gi > 0 || groupOrder.length > 1)) {
            const header = razyui.el('div', { textContent: g });
            header.attr('style', 'padding:6px 12px 2px;font-size:0.68rem;font-weight:600;letter-spacing:0.04em;text-transform:uppercase;color:var(--be-text-muted);');
            menu.append(header);
        }
        byGroup.get(g).forEach(it => {
            if (it.separator) {
                const sep = razyui.el('div');
                sep.attr('style', 'height:1px;background:var(--be-border);margin:4px 0;');
                menu.append(sep);
                return;
            }
            const row = razyui.el('div', {
                className: 'block-handle-menu-item',
                'data-menu-id': it.id,
                role: 'menuitem',
            });
            if (it.hasSubmenu) row.attr('data-has-submenu', 'true');
            row.attr('style', [
                'display:flex',
                'align-items:center',
                'gap:8px',
                'padding:6px 12px',
                'cursor:pointer',
                'user-select:none',
                'color:var(--be-text)',
                'transition:background 0.1s',
            ].join(';'));
            const iconHtml = it.icon ? `<span style="width:20px;display:inline-flex;justify-content:center;color:var(--be-text-muted);">${it.icon}</span>` : '<span style="width:20px;"></span>';
            // Items that open a submenu show a right-chevron instead of the
            // ``desc`` text — Notion convention, signals "hover opens more".
            const tailHtml = it.hasSubmenu
                ? '<span class="block-handle-menu-chevron" style="margin-left:auto;color:var(--be-text-muted);font-size:0.9rem;line-height:1;">\u203A</span>'
                : (it.desc ? `<span style="margin-left:auto;font-size:0.72rem;color:var(--be-text-muted);">${it.desc}</span>` : '');
            row.html(`${iconHtml}<span style="flex:1;">${it.label}</span>${tailHtml}`);
            row.on('mouseenter', () => row.css('background', 'var(--be-bg-hover)'));
            row.on('mouseleave', () => row.css('background', ''));
            menu.append(row);
        });
    });

    if (!items.filter(i => !i.separator).length) {
        const empty = razyui.el('div', { textContent: 'No actions available' });
        empty.attr('style', 'padding:10px 12px;color:var(--be-text-muted);font-size:0.8rem;');
        menu.append(empty);
    }

    return menu[0];
}
