/**
 * Native editable table block for BlockEditor (Notion-style).
 *
 * @module BlockEditor/plugins/table-block
 */

/**
 * @param {unknown} rows
 * @returns {string[][]}
 */
export function normalizeTableRows(rows) {
    if (!Array.isArray(rows) || rows.length === 0) {
        return [
            ['', ''],
            ['', ''],
        ];
    }
    const out = [];
    let maxCols = 0;
    for (const row of rows) {
        if (!Array.isArray(row)) continue;
        const cells = row.map((c) => String(c ?? ''));
        maxCols = Math.max(maxCols, cells.length);
        out.push(cells);
    }
    if (!out.length) {
        return [
            ['', ''],
            ['', ''],
        ];
    }
    const cols = Math.max(2, maxCols);
    return out.map((row) => {
        const copy = row.slice();
        while (copy.length < cols) copy.push('');
        return copy;
    });
}

/**
 * @param {string[][]} rows
 */
function rowsToMarkdown(rows) {
    const norm = normalizeTableRows(rows);
    if (!norm.length) return '';
    const header = norm[0];
    const sep = header.map(() => '---');
    const body = norm.slice(1);
    const lines = [
        `| ${header.join(' | ')} |`,
        `| ${sep.join(' | ')} |`,
        ...body.map((r) => `| ${r.join(' | ')} |`),
    ];
    return lines.join('\n');
}

/**
 * @param {typeof import('../index.js').default} BlockEditor
 */
export function registerTableBlockType(BlockEditor) {
    if (BlockEditor.__ruiTableBlockRegistered) return;
    BlockEditor.__ruiTableBlockRegistered = true;

    BlockEditor.registerBlockType({
        type: 'table',
        label: 'Table',
        desc: 'Editable table with rows and columns',
        icon: '⊞',
        group: 'Basic',
        /**
         * @param {{ meta?: { rows?: string[][] }, content?: string }} block
         * @param {HTMLElement} mount
         * @param {{ fireChange: () => void }} api
         */
        render(block, mount, api) {
            if (!block.meta || typeof block.meta !== 'object') {
                block.meta = {};
            }
            const rows = normalizeTableRows(block.meta.rows);
            block.meta.rows = rows;

            const wrap = document.createElement('div');
            wrap.className = 'block-table-wrap';

            const table = document.createElement('table');
            table.className = 'block-table';
            table.setAttribute('role', 'table');

            const syncFromDom = () => {
                const next = [];
                for (const tr of table.rows) {
                    const row = [];
                    for (const td of tr.cells) {
                        row.push(td.textContent || '');
                    }
                    next.push(row);
                }
                block.meta.rows = normalizeTableRows(next);
                block.content = '';
                api.fireChange();
            };

            const rebuild = () => {
                table.replaceChildren();
                const data = normalizeTableRows(block.meta.rows);
                block.meta.rows = data;
                for (const row of data) {
                    const tr = document.createElement('tr');
                    for (const cell of row) {
                        const td = document.createElement('td');
                        td.contentEditable = 'true';
                        td.textContent = cell;
                        td.addEventListener('input', syncFromDom);
                        tr.append(td);
                    }
                    table.append(tr);
                }
            };

            rebuild();

            const bar = document.createElement('div');
            bar.className = 'block-table-bar';

            const addRowBtn = document.createElement('button');
            addRowBtn.type = 'button';
            addRowBtn.className = 'block-table-bar-btn';
            addRowBtn.textContent = '+ Row';
            addRowBtn.addEventListener('click', (ev) => {
                ev.preventDefault();
                const cols = block.meta.rows[0]?.length || 2;
                block.meta.rows.push(Array.from({ length: cols }, () => ''));
                rebuild();
                api.fireChange();
            });

            const addColBtn = document.createElement('button');
            addColBtn.type = 'button';
            addColBtn.className = 'block-table-bar-btn';
            addColBtn.textContent = '+ Column';
            addColBtn.addEventListener('click', (ev) => {
                ev.preventDefault();
                block.meta.rows = block.meta.rows.map((row) => [...row, '']);
                rebuild();
                api.fireChange();
            });

            bar.append(addRowBtn, addColBtn);
            wrap.append(bar, table);
            mount.append(wrap);
        },
        /**
         * @param {{ meta?: { rows?: string[][] } }} block
         */
        toMarkdown(block) {
            return rowsToMarkdown(block.meta?.rows || []);
        },
    });

    if (typeof BlockEditor.registerCommand === 'function') {
        BlockEditor.registerCommand({
            label: 'Table',
            type: 'table',
            icon: '⊞',
            desc: 'Insert editable table',
            meta: { rows: normalizeTableRows(null) },
            handler(editor, blockId) {
                editor.convertBlock(blockId, 'table', {
                    rows: normalizeTableRows(null),
                });
            },
        });
    }
}

export default registerTableBlockType;
