/**
 * @fileoverview BlockEditor — modular entry point.
 *
 * Orchestrates sub-modules:
 *   constants.js — block type definitions, defaults, plugin registries
 *   helpers.js   — HTML/Markdown conversion, caret utilities, inline formatting
 *   state.js     — reactive state creation
 *   view.js      — DOM construction (blocks, toolbar, slash menu, format bar)
 *   events.js    — keyboard, drag-drop, selection, slash-menu events
 *
 * @module module/BlockEditor
 */

import { default as razyui } from '../../index.js';

import {
    DEFAULTS,
    customCommands,
    customBlockTypes,
    registerCommand,
    unregisterCommand,
    registerBlockType,
    unregisterBlockType,
    PART,
} from './constants.js';
import { getMarkdownEditor, htmlToMd, newBlockId } from './helpers.js';
import { createState } from './state.js';
import { renderBlockWrapper, renderBlockContent, buildFormatBar, buildSlashMenu } from './view.js';
import { emitEvent } from '../shared/emitEvent.js';
import { initGlobalListeners, initDelegatedListeners } from './events.js';
import { createPluginHost } from './plugin-host.js';
import { createVirtualizer } from './virtualizer.js';

/**
 * BlockEditor — v2
 *
 * A Notion-like block-based editor integrated with MarkdownEditor.
 * Each content unit is a typed "block" — paragraphs, headings, lists,
 * code, images, quotes, dividers, callouts, and toggles.
 *
 * Features:
 *   - Contenteditable text blocks with inline formatting
 *   - / slash command to create new block types
 *   - Drag-and-drop reorder via block handle
 *   - Inline formatting toolbar on text selection (bold, italic, etc.)
 *   - Turn-into menu to convert block types
 *   - Block-level keyboard navigation (Arrow keys, Enter, Backspace)
 *   - Import / export Markdown (via MarkdownEditor.parse / tokenize)
 *   - Editable page title
 *   - Callbacks: onChange, onBlockAdd, onBlockRemove, onBlockMove
 *   - Programmatic API via getControl()
 *
 * Block types:
 *   paragraph, heading (h1/h2/h3), bulleted-list, numbered-list, todo,
 *   code, quote, divider, callout, toggle, image
 *
 * @param {string|Element} selector — CSS selector or Element for the container
 * @param {object}   config
 * @param {string}   [config.title]        — editable page title (default '')
 * @param {Array}    [config.blocks]       — initial block data array
 * @param {string}   [config.markdown]     — initial content as markdown (alternative to blocks)
 * @param {string}   [config.placeholder]  — placeholder for empty first block
 * @param {boolean}  [config.titleEditable] — allow editing the title (default true)
 * @param {function} [config.onChange]      — (blocks) => void
 * @param {function} [config.onBlockAdd]   — (block, index) => void
 * @param {function} [config.onBlockRemove] — (block, index) => void
 * @param {function} [config.onBlockMove]  — (block, fromIndex, toIndex) => void
 * @param {Array<Object|Function>} [config.plugins] — per-instance plugins.
 *        Each plugin is either a function `(pluginCtx) => destroy?` or an
 *        object `{ name, init(pluginCtx), destroy? }`. See plugin-api.md.
 */
const BlockEditor = class {
    // ── Private fields ───────────────────────────
    #target = null;
    #container = null;
    #titleEl = null;
    #contentEl = null;
    #blocks = [];
    #blockElements = new Map();  // id → DOM wrapper element
    #config = {};
    #stateRef = null;
    #setState = null;
    #destroyed = false;

    // Slash command menu
    #slashMenu = null;
    #slashMenuVisible = false;
    #slashFilterText = '';
    #slashActiveIndex = 0;
    #slashTargetBlockId = null;
    #slashAllItems = [];  // combined built-in + custom commands

    // Inline formatting toolbar
    #formatBar = null;
    #formatBarVisible = false;

    // Drag state
    #dragBlockId = null;
    #dragIndicator = null;
    #dragOverIndex = -1;

    // Lite MarkdownEditor instances (block id → MarkdownEditor instance)
    #liteEditors = new Map();

    // Plugin host (registries, emitter, overlays, lifecycle).
    #pluginHost = null;

    // Viewport virtualizer (mounts/unmounts block contents as user scrolls).
    #virtualizer = null;
    // True while the editor is bulk-loading initial blocks (cfg.blocks /
    // cfg.markdown). Used by #addBlock to defer content rendering when the
    // virtualizer is active, so opening a 10k-block document is fast.
    #bulkLoading = false;

    // Cached context object
    #_ctx = null;
    #eventAC = new AbortController();

    // ── Mutation op log ──────────────────────────
    //
    // Every structural mutation (insert / delete / move / convert / content
    // update) pushes an op descriptor here. Hosts read the queue via
    // ``getControl().getPendingOps()`` to ship a minimal delta to the server
    // instead of re-sending ``blocks_json`` on every commit. The queue is
    // in DOM order; callers are expected to call ``clearPendingOps()``
    // after a successful commit.
    //
    // Ops are NOT recorded while ``#bulkLoading`` is true (initial
    // hydration from ``config.blocks`` / ``setBlocks`` / ``setMarkdown``)
    // — those entries are already on the server or are replacing the
    // whole document, so per-op tracking would double-count.
    #pendingOps = [];

    // ── Context bridge ──────────────────────────
    /**
     * Build a thin context object that sub-module functions can use
     * to access private editor state without exposing #fields directly.
     */
    #ctx() {
        if (!this.#_ctx) {
            const self = this;
            this.#_ctx = {
                get razyui()            { return razyui; },
                get editorInstance()     { return self; },
                get config()            { return self.#config; },
                get container()         { return self.#container; },
                get signal()            { return self.#eventAC.signal; },
                get titleEl()           { return self.#titleEl; },
                get contentEl()         { return self.#contentEl; },
                get blocks()            { return self.#blocks; },
                set blocks(v)           { self.#blocks = v; },
                get blockElements()     { return self.#blockElements; },
                get liteEditors()       { return self.#liteEditors; },

                // Slash menu state
                get slashMenu()          { return self.#slashMenu; },
                set slashMenu(v)         { self.#slashMenu = v; },
                get slashMenuVisible()   { return self.#slashMenuVisible; },
                set slashMenuVisible(v)  { self.#slashMenuVisible = v; },
                get slashFilterText()    { return self.#slashFilterText; },
                set slashFilterText(v)   { self.#slashFilterText = v; },
                get slashActiveIndex()   { return self.#slashActiveIndex; },
                set slashActiveIndex(v)  { self.#slashActiveIndex = v; },
                get slashTargetBlockId() { return self.#slashTargetBlockId; },
                set slashTargetBlockId(v){ self.#slashTargetBlockId = v; },
                get slashAllItems()      { return self.#slashAllItems; },
                set slashAllItems(v)     { self.#slashAllItems = v; },

                // Format bar state
                get formatBar()          { return self.#formatBar; },
                set formatBar(v)         { self.#formatBar = v; },
                get formatBarVisible()   { return self.#formatBarVisible; },
                set formatBarVisible(v)  { self.#formatBarVisible = v; },

                // Drag state
                get dragBlockId()        { return self.#dragBlockId; },
                set dragBlockId(v)       { self.#dragBlockId = v; },
                get dragIndicator()      { return self.#dragIndicator; },
                set dragIndicator(v)     { self.#dragIndicator = v; },
                get dragOverIndex()      { return self.#dragOverIndex; },
                set dragOverIndex(v)     { self.#dragOverIndex = v; },

                // Reactive state
                get stateRef()           { return self.#stateRef; },
                set stateRef(v)          { self.#stateRef = v; },
                get setState()           { return self.#setState; },
                set setState(v)          { self.#setState = v; },

                // Plugin host (registries, emitter, overlays) — present after #init.
                get plugins()            { return self.#pluginHost; },

                // Delegated methods
                addBlock:           (type, afterId, content, meta) => self.#addBlock(type, afterId, content, meta),
                removeBlock:        (id) => self.#removeBlock(id),
                moveBlock:          (id, newIndex) => self.#moveBlock(id, newIndex),
                convertBlock:       (id, newType, newMeta) => self.#convertBlock(id, newType, newMeta),
                focusBlock:         (id, position) => self.#focusBlock(id, position),
                getEditableInBlock: (id) => self.#getEditableInBlock(id),
                fireChange:         () => self.#fireChange(),
                rerenderBlockContent: (id) => {
                    const block = self.#blocks.find(b => b.id === id);
                    if (!block) return;
                    const wrapper = self.#blockElements.get(id);
                    if (!wrapper) return;
                    const oldContent = wrapper.find('.block-content');
                    if (!oldContent[0]) return;
                    const newContent = renderBlockContent(self.#ctx(), block);
                    oldContent[0].replaceWith(newContent[0]);
                    // Re-rendering counts as a "materialize" — the new
                    // content is real, not a placeholder. Refresh the
                    // virtualizer's height cache for it.
                    self.#virtualizer?.ensureMaterialized(id);
                    self.#virtualizer?.recordHeight(id);
                },
            };
        }
        return this.#_ctx;
    }

    // ── Plugin: Custom slash commands ────────────

    /**
     * Register a custom slash command.
     * @param {object} config
     * @param {string} config.type    — block type to create (or custom identifier)
     * @param {string} config.label   — display name in slash menu
     * @param {string} config.desc    — description in slash menu
     * @param {string} config.icon    — icon character
     * @param {object} [config.meta]  — default meta for the new block
     * @param {function} [config.handler] — (editor, blockId) => void; if provided, called instead of default block creation
     */
    static registerCommand(config) { registerCommand(config); }

    /**
     * Remove a registered custom command by label.
     */
    static unregisterCommand(label) { unregisterCommand(label); }

    /**
     * Get all registered custom commands (read-only copy).
     */
    static get customCommands() {
        return customCommands.map(c => ({ ...c }));
    }

    // ── Plugin: Custom block types ──────────────

    /**
     * Register a custom block type.
     * @param {object} config
     * @param {string} config.type        — unique block type identifier
     * @param {string} config.label       — display label
     * @param {string} config.desc        — description
     * @param {string} config.icon        — icon character
     * @param {function} config.render    — (block, container, api) => void; build DOM inside container
     *   api: { fireChange(), getEditableInBlock(id), focusBlock(id), addBlock(...), removeBlock(id) }
     * @param {function} [config.toMarkdown] — (block) => string; export block as markdown
     * @param {function} [config.onDestroy]  — (block) => void; cleanup when block is removed
     */
    static registerBlockType(config) { registerBlockType(config); }

    /**
     * Remove a registered custom block type.
     */
    static unregisterBlockType(type) { unregisterBlockType(type); }

    /**
     * Get all registered custom block type names.
     */
    static get customBlockTypeNames() {
        return [...customBlockTypes.keys()];
    }

    // ── Constructor ──────────────────────────────
    constructor(selector, config = {}) {
        this.#config = { ...DEFAULTS, ...config };

        const el = razyui(selector)[0];
        if (!el) {
            console.warn('BlockEditor: element not found \u2192', selector);
            return;
        }
        this.#target = el;
        this.#init();
    }

    // ═══════════════════════════════════════════════
    // Initialization
    // ═══════════════════════════════════════════════

    #init() {
        const cfg = this.#config;
        const ctx = this.#ctx();

        // ── Reactive state ──
        const [stateRef, setState] = createState(razyui);
        this.#stateRef = stateRef;
        this.#setState = setState;

        // ── Build DOM ──
        const container = razyui.el('div', { className: 'block-editor' });
        PART.ROOT.apply(container);
        this.#container = container;

        // Title
        const titleEl = razyui.el('h1', {
            className: 'block-editor-title',
            contentEditable: cfg.titleEditable ? 'true' : 'false',
            'data-placeholder': 'Untitled',
            textContent: cfg.title,
        });
        PART.TITLE.apply(titleEl);
        titleEl.on('keydown', (e) => {
            if (e.key === 'Enter') {
                e.preventDefault();
                // Focus first block
                if (this.#blocks.length) this.#focusBlock(this.#blocks[0].id);
            }
        });
        this.#titleEl = titleEl;
        container.append(titleEl);

        // Content area
        const contentEl = razyui.el('div', { className: 'block-editor-content' });
        PART.CONTENT.apply(contentEl);
        this.#contentEl = contentEl;
        container.append(contentEl);

        // ── Plugin host (must exist before view builds menus) ──
        this.#pluginHost = createPluginHost(ctx);

        // ── Floating elements ──
        this.#slashMenu = buildSlashMenu(ctx);
        container.append(this.#slashMenu);

        this.#formatBar = buildFormatBar(ctx);
        container.append(this.#formatBar);

        this.#dragIndicator = razyui.el('div', { className: 'block-drag-indicator' });
        PART.DRAG_INDICATOR.apply(this.#dragIndicator);
        container.append(this.#dragIndicator);

        // ── Mount ──
        razyui(this.#target).append(container);

        // ── Virtualizer (must exist before #addBlock runs so it can
        //    defer content rendering during bulk load). ──
        const virtOpts = (cfg.virtualize === false)
            ? { enabled: false }
            : (typeof cfg.virtualize === 'object' && cfg.virtualize !== null)
                ? cfg.virtualize
                : {};
        this.#virtualizer = createVirtualizer(ctx, virtOpts);

        // ── Load initial blocks (bulk = true → placeholders, not real
        //    content, when virtualizer is active). ──
        this.#bulkLoading = true;
        if (cfg.blocks && Array.isArray(cfg.blocks)) {
            // Preserve server-assigned block ids on hydration — without
            // this, the editor would mint a fresh UUID for every loaded
            // block and the next AI call would point at an id the sidecar
            // has never seen (U.7 regression ``NotFound selection_block_id``).
            cfg.blocks.forEach(b => this.#addBlock(b.type, null, b.content, b.meta, b.id || null));
            this.#bulkLoading = false;
            this.#virtualizer.attach();
            this.#resetOpTracking();
        } else if (cfg.markdown) {
            this.#importMarkdown(cfg.markdown).then(() => {
                if (!this.#blocks.length) this.#addBlock('paragraph');
                this.#bulkLoading = false;
                this.#virtualizer.attach();
                this.#resetOpTracking();
            });
        } else {
            this.#bulkLoading = false;
            this.#resetOpTracking();
        }

        // Ensure at least one empty paragraph
        if (!cfg.markdown && !this.#blocks.length) {
            this.#addBlock('paragraph');
        }

        // ── Global selection listener for format bar ──
        // ── Close slash menu on outside click ──
        initGlobalListeners(ctx);
        initDelegatedListeners(ctx);

        // ── Install user plugins (after listeners so plugins can react) ──
        const userPlugins = Array.isArray(cfg.plugins) ? cfg.plugins : [];
        userPlugins.forEach(p => this.#pluginHost.installPlugin(p));
    }

    // ═══════════════════════════════════════════════
    // Block management
    // ═══════════════════════════════════════════════

    /**
     * Create and insert a block.
     * @param {string} type
     * @param {string|null} afterId — insert after this block, or null for append
     * @param {string} [content]
     * @param {object} [meta]
     * @param {string} [idOverride] — reuse a known block_id (e.g. when
     *        rehydrating from the server, or replaying ops). When absent,
     *        a fresh UUID v4 is generated.
     * @returns {object} — the new block data
     */
    #addBlock(type, afterId = null, content = '', meta = {}, idOverride = null) {
        const block = {
            id: (typeof idOverride === 'string' && idOverride) ? idOverride : newBlockId(),
            type,
            content: content || '',
            meta: Object.assign({}, meta),
        };

        // Determine insertion index
        let index;
        if (afterId) {
            const afterIdx = this.#blocks.findIndex(b => b.id === afterId);
            index = afterIdx >= 0 ? afterIdx + 1 : this.#blocks.length;
        } else {
            index = this.#blocks.length;
        }

        this.#blocks.splice(index, 0, block);

        // Build and mount DOM
        const wrapper = renderBlockWrapper(this.#ctx(), block);
        this.#blockElements.set(block.id, wrapper);

        if (index < this.#blocks.length - 1) {
            const nextBlock = this.#blocks[index + 1];
            const nextEl = this.#blockElements.get(nextBlock.id);
            nextEl.before(wrapper);
        } else {
            this.#contentEl.append(wrapper);
        }

        // ── Virtualizer: during bulk load, swap freshly-rendered content
        //    for a cheap placeholder; the IntersectionObserver will
        //    materialize blocks as the user scrolls them into view.
        //    For incremental adds we leave the content as-is (the new
        //    block almost always wants to be visible / focused) but still
        //    register it so it can be demoted later when scrolled away. ──
        if (this.#virtualizer) {
            if (this.#virtualizer.shouldDeferInitial({ bulk: this.#bulkLoading })) {
                this.#virtualizer.renderInitialPlaceholder(wrapper, block.id);
            }
            this.#virtualizer.observeWrapper(wrapper);
        }

        this.#setState({ blockCount: this.#blocks.length });

        // Record an ``insert`` op for the delta-commit path. Skip during
        // bulk load — those blocks came from the server and are already
        // persisted. ``after_block_id`` is the id of the block that now
        // precedes us (derived from ``index``); null means "prepend".
        if (!this.#bulkLoading) {
            const afterBlockId = index > 0 ? this.#blocks[index - 1].id : null;
            this.#pushOp({
                op: 'insert',
                block_id: block.id,
                after_block_id: afterBlockId,
                at_index: index,
                type: block.type,
                content: block.content,
                meta: { ...block.meta },
            });
        }

        emitEvent(this.#container[0], 'add', { block, index });
        this.#pluginHost?.emit('block:add', { block, index });
        if (typeof this.#config.onBlockAdd === 'function') {
            this.#config.onBlockAdd(block, index);
        }

        return block;
    }

    /**
     * Remove a block by ID.
     */
    #removeBlock(id) {
        const idx = this.#blocks.findIndex(b => b.id === id);
        if (idx === -1) return;

        const block = this.#blocks[idx];
        this.#blocks.splice(idx, 1);

        // Cleanup lite MarkdownEditor instance
        const liteEditor = this.#liteEditors.get(id);
        if (liteEditor) {
            liteEditor.destroy();
            this.#liteEditors.delete(id);
        }

        // Cleanup custom block type onDestroy
        const customType = customBlockTypes.get(block.type);
        if (customType && typeof customType.onDestroy === 'function') {
            customType.onDestroy(block);
        }

        const el = this.#blockElements.get(id);
        if (el) {
            this.#virtualizer?.unobserveWrapper(el);
            el[0].remove();
        }
        this.#blockElements.delete(id);

        this.#setState({ blockCount: this.#blocks.length });

        // Record a ``delete`` op unless this removal is part of a bulk
        // re-hydration (``setBlocks`` / ``setMarkdown`` clear the list
        // before re-adding — the delta wire path shouldn't see those).
        if (!this.#bulkLoading) {
            this.#pushOp({ op: 'delete', block_id: id });
        }

        emitEvent(this.#container[0], 'remove', { block, index: idx });
        this.#pluginHost?.emit('block:remove', { block, index: idx });
        if (typeof this.#config.onBlockRemove === 'function') {
            this.#config.onBlockRemove(block, idx);
        }

        // Ensure at least one block
        if (!this.#blocks.length) {
            const newBlock = this.#addBlock('paragraph');
            this.#focusBlock(newBlock.id);
        }
    }

    /**
     * Move a block from its current position to newIndex.
     */
    #moveBlock(id, newIndex) {
        const oldIdx = this.#blocks.findIndex(b => b.id === id);
        if (oldIdx === -1 || oldIdx === newIndex) return;

        const block = this.#blocks.splice(oldIdx, 1)[0];
        this.#blocks.splice(newIndex, 0, block);

        // Reorder DOM
        const el = this.#blockElements.get(id);
        if (newIndex >= this.#blocks.length - 1) {
            this.#contentEl.append(el);
        } else {
            const nextBlock = this.#blocks[newIndex + 1];
            const nextEl = this.#blockElements.get(nextBlock?.id);
            if (nextEl) nextEl.before(el);
        }

        // Record a ``move`` op. ``after_block_id`` is computed from the
        // post-move position (null ⇒ moved to the top). Hosts prefer the
        // positional anchor over ``at_index`` when replaying against a
        // server that may have applied concurrent inserts.
        if (!this.#bulkLoading) {
            const afterBlockId = newIndex > 0 ? this.#blocks[newIndex - 1].id : null;
            this.#pushOp({
                op: 'move',
                block_id: id,
                after_block_id: afterBlockId,
                at_index: newIndex,
            });
        }

        emitEvent(this.#container[0], 'move', { block, fromIndex: oldIdx, toIndex: newIndex });
        this.#pluginHost?.emit('block:move', { block, fromIndex: oldIdx, toIndex: newIndex });
        if (typeof this.#config.onBlockMove === 'function') {
            this.#config.onBlockMove(block, oldIdx, newIndex);
        }

        this.#fireChange();
    }

    /**
     * Convert a block to a different type.
     *
     * Content-preservation policy (matches Notion's "Turn into"):
     *   • text ↔ text      → keep ``content`` verbatim (paragraph ↔
     *     heading ↔ list ↔ to-do ↔ quote ↔ callout ↔ code ↔ toggle).
     *   • text → non-text  → drop ``content`` (divider, image, columns,
     *     synced block, page, embed, …) — the new block has no text
     *     slot so the old text would just linger invisibly.
     *   • meta              → replaced, not merged, whenever the *type*
     *     itself changes, so a Heading 2's ``level:2`` doesn't silently
     *     survive a conversion into a paragraph / code block / image.
     */
    #convertBlock(id, newType, newMeta = {}) {
        const block = this.#blocks.find(b => b.id === id);
        if (!block) return;

        // Cleanup lite MarkdownEditor if converting away from regular
        const liteEditor = this.#liteEditors.get(id);
        if (liteEditor) {
            liteEditor.destroy();
            this.#liteEditors.delete(id);
        }

        // Canonical list of block types that carry NO inline text content.
        // Keep in sync with built-in + common plugin types; unknown types
        // default to text-bearing which is the safe (non-destructive) path.
        const NON_TEXT_TYPES = new Set([
            'divider', 'image', 'video', 'audio', 'file', 'embed',
            'columns', 'column', 'synced-block', 'page', 'page-link',
            'equation', 'block-equation',
        ]);

        const typeChanged = block.type !== newType;

        block.type = newType;
        if (typeChanged) {
            // Replace meta wholesale — prevents stale fields like ``level``
            // from a previous Heading 2 leaking into the new block type.
            block.meta = { ...(newMeta || {}) };
        } else {
            Object.assign(block.meta, newMeta);
        }
        if (NON_TEXT_TYPES.has(newType)) {
            block.content = '';
        }

        // Record the type/meta/content change. When we convert INTO a
        // non-text type we also cleared ``content`` above, so the delta
        // must carry the new (empty) content or the server will keep
        // the old text on its side and the next hydrate will resurrect
        // it.
        if (!this.#bulkLoading) {
            const op = {
                op: 'update',
                block_id: id,
                type: block.type,
                meta: { ...block.meta },
                fields: ['type', 'meta'],
            };
            if (NON_TEXT_TYPES.has(newType)) {
                op.content = block.content;
                op.fields.push('content');
            }
            this.#pushOp(op);
        }

        // Re-render the block
        const oldEl = this.#blockElements.get(id);
        if (oldEl) this.#virtualizer?.unobserveWrapper(oldEl);
        const newEl = renderBlockWrapper(this.#ctx(), block);
        this.#blockElements.set(id, newEl);
        oldEl[0].replaceWith(newEl[0]);
        this.#virtualizer?.observeWrapper(newEl);

        // Same contract as #moveBlock: hosts (library save, dirty) listen
        // for ``change``; keyboard paths that only push ops and re-render
        // must also emit.
        this.#fireChange();

        // Focus the new editable
        requestAnimationFrame(() => this.#focusBlock(id));
    }

    // ═══════════════════════════════════════════════
    // Caret / focus utilities
    // ═══════════════════════════════════════════════

    /**
     * Focus a block's editable element.
     * @param {string} id
     * @param {'start'|'end'|number} position — cursor position
     */
    #focusBlock(id, position = 'end') {
        // Make sure the block is mounted before we try to focus into it.
        this.#virtualizer?.ensureMaterialized(id);

        // For regular blocks (lite MarkdownEditor), focus the WYSIWYG element
        const liteEditor = this.#liteEditors.get(id);
        if (liteEditor) {
            liteEditor.getControl().focus();
            return;
        }

        const el = this.#getEditableInBlock(id);
        if (!el?.[0]) return;
        el[0].focus();

        const sel = window.getSelection();
        const range = document.createRange();

        if (position === 'start') {
            range.selectNodeContents(el[0]);
            range.collapse(true);
        } else if (position === 'end') {
            range.selectNodeContents(el[0]);
            range.collapse(false);
        } else if (typeof position === 'number') {
            // Set caret at character offset
            const walker = document.createTreeWalker(el[0], NodeFilter.SHOW_TEXT, null);
            let curr = 0;
            let node;
            while ((node = walker.nextNode())) {
                if (curr + node.length >= position) {
                    range.setStart(node, position - curr);
                    range.collapse(true);
                    break;
                }
                curr += node.length;
            }
            if (!node) {
                range.selectNodeContents(el[0]);
                range.collapse(false);
            }
        }

        sel.removeAllRanges();
        sel.addRange(range);
    }

    /**
     * Get the primary editable element inside a block wrapper.
     */
    #getEditableInBlock(id) {
        const wrapper = this.#blockElements.get(id);
        if (!wrapper) return null;
        // If the wrapper is currently a virtualized placeholder, materialize
        // first so the contenteditable actually exists.
        this.#virtualizer?.ensureMaterialized(id);
        return wrapper.find('[contenteditable="true"]');
    }

    // ═══════════════════════════════════════════════
    // Change notification
    // ═══════════════════════════════════════════════

    #fireChange() {
        const blocks = this.#blocks.map(b => ({
            id: b.id,
            type: b.type,
            content: b.content,
            meta: { ...b.meta },
        }));
        emitEvent(this.#container[0], 'change', { value: blocks, blocks });
        this.#pluginHost?.emit('change', { blocks });
        if (typeof this.#config.onChange === 'function') {
            this.#config.onChange(blocks);
        }
    }

    // ═══════════════════════════════════════════════
    // Op tracking (delta commits)
    // ═══════════════════════════════════════════════
    //
    // The BlockEditor records every user-originated mutation as a
    // descriptive op ({op, block_id, ...}) and also keeps a content
    // snapshot map. ``getPendingOps()`` reconciles the two at flush time:
    // explicit structural ops (insert/delete/move/convert) go out first,
    // then any block whose current ``content`` differs from the snapshot
    // contributes a lightweight ``update`` op.
    //
    // This flush-time content diff is a safety net: mutation sites that
    // don't explicitly record content changes (keyboard shortcuts that
    // call ``document.execCommand('bold')`` and then ``block.content = el.html()``
    // without going through the plugin host) still get captured, so the
    // server never loses an edit even when a new mutation path forgets
    // to emit an op.

    /**
     * Append a raw op descriptor to the queue. Plugins listen for
     * ``block:op`` on the pluginHost; hosts read the final, reconciled
     * list via ``getPendingOps()``.
     *
     * @param {{op: string, block_id: string, [key:string]: any}} op
     */
    #pushOp(op) {
        this.#pendingOps.push(op);
        this.#pluginHost?.emit('block:op', { op });
    }

    /**
     * Reset the op log + content snapshot to "clean" — the current
     * ``#blocks`` state becomes the new baseline. Called after a
     * successful commit (host calls ``clearPendingOps``) and after bulk
     * hydration (``setBlocks`` / ``setMarkdown`` / initial config).
     */
    #resetOpTracking() {
        this.#pendingOps.length = 0;
        this.#contentSnapshot = new Map();
        for (const b of this.#blocks) {
            this.#contentSnapshot.set(b.id, b.content || '');
        }
    }

    /**
     * Compute the reconciled op list: explicit structural ops + content
     * diffs against the snapshot, compacted to drop insert+delete pairs.
     *
     * Ordering guarantee: ops come out in the same relative order they
     * were recorded; content updates are appended at the end (they
     * depend on the structural shape being correct first, and they
     * cannot reference a block that a later op deletes since those
     * deletes already preceded them in the structural log).
     *
     * @returns {Array<Object>}
     */
    #computePendingOps() {
        // Pass 1 — build insert/delete sets for compaction.
        const insertIds = new Set();
        const deleteIds = new Set();
        for (const o of this.#pendingOps) {
            if (o.op === 'insert') insertIds.add(o.block_id);
            else if (o.op === 'delete') deleteIds.add(o.block_id);
        }
        // Insert+delete in the same batch cancel out.
        const cancelled = new Set([...insertIds].filter(id => deleteIds.has(id)));

        // Pass 2 — emit structural ops, refreshing insert payloads with
        // current content/type/meta (so post-insert typing rides along
        // without a separate update).
        const out = [];
        for (const o of this.#pendingOps) {
            if (cancelled.has(o.block_id)) continue;
            if (o.op === 'insert') {
                const idx = this.#blocks.findIndex(b => b.id === o.block_id);
                if (idx < 0) continue;
                const b = this.#blocks[idx];
                const afterBlockId = idx > 0 ? this.#blocks[idx - 1].id : null;
                out.push({
                    op: 'insert',
                    block_id: b.id,
                    after_block_id: afterBlockId,
                    at_index: idx,
                    type: b.type,
                    content: b.content,
                    meta: { ...b.meta },
                });
            } else if (o.op === 'move') {
                if (insertIds.has(o.block_id)) continue; // insert carries final position
                const idx = this.#blocks.findIndex(b => b.id === o.block_id);
                if (idx < 0) continue;
                const afterBlockId = idx > 0 ? this.#blocks[idx - 1].id : null;
                out.push({
                    op: 'move',
                    block_id: o.block_id,
                    after_block_id: afterBlockId,
                    at_index: idx,
                });
            } else if (o.op === 'delete') {
                out.push({ op: 'delete', block_id: o.block_id });
            } else if (o.op === 'update') {
                if (insertIds.has(o.block_id)) continue; // insert carries final state
                const b = this.#blocks.find(bl => bl.id === o.block_id);
                if (!b) continue;
                const fields = Array.isArray(o.fields) && o.fields.length
                    ? o.fields
                    : ['content'];
                const upd = { op: 'update', block_id: o.block_id, fields };
                if (fields.includes('type')) upd.type = b.type;
                if (fields.includes('content')) upd.content = b.content;
                if (fields.includes('meta')) upd.meta = { ...b.meta };
                out.push(upd);
            }
        }

        // Pass 3 — content diff. Catches mutation sites that bypass the
        // op log (keyboard shortcuts, paste handlers, legacy format-bar
        // commands). Skip blocks that were just inserted (content is in
        // the insert) or are in a pending delete.
        const alreadyUpdated = new Set();
        for (const o of out) {
            if (o.op === 'update' && o.fields.includes('content')) {
                alreadyUpdated.add(o.block_id);
            }
        }
        for (const b of this.#blocks) {
            if (insertIds.has(b.id) || cancelled.has(b.id)) continue;
            if (alreadyUpdated.has(b.id)) continue;
            const snap = this.#contentSnapshot.get(b.id);
            if (snap === undefined) continue; // unseen block — can't be dirty
            if (snap !== b.content) {
                out.push({
                    op: 'update',
                    block_id: b.id,
                    fields: ['content'],
                    content: b.content,
                });
            }
        }

        return out;
    }

    // Snapshot of block-id → content at the last known-clean point.
    #contentSnapshot = new Map();

    // ═══════════════════════════════════════════════
    // Markdown integration
    // ═══════════════════════════════════════════════

    /**
     * Import Markdown string into blocks.
     */
    async #importMarkdown(md) {
        const MarkdownEditor = await getMarkdownEditor();
        const tokens = MarkdownEditor.tokenize(md);
        tokens.forEach(token => {
            this.#addBlock(token.type, null, token.content, token.meta || {});
        });
    }

    /**
     * Export current blocks as a Markdown string.
     */
    #exportMarkdown() {
        return this.#blocks.map(block => {
            // Check custom block type toMarkdown first
            const customType = customBlockTypes.get(block.type);
            if (customType && typeof customType.toMarkdown === 'function') {
                return customType.toMarkdown(block);
            }

            // For regular (lite markdown) blocks, content is raw markdown already
            const content = (block.type === 'regular')
                ? block.content
                : htmlToMd(block.content);

            switch (block.type) {
                case 'heading':
                    return '#'.repeat(block.meta.level || 1) + ' ' + content;
                case 'bulleted-list':
                    return '- ' + content;
                case 'numbered-list':
                    return '1. ' + content;
                case 'todo':
                    return `- [${block.meta.checked ? 'x' : ' '}] ${content}`;
                case 'code':
                    return '```' + (block.meta.language || '') + '\n' + block.content + '\n```';
                case 'quote':
                    return content.split('\n').map(l => '> ' + l).join('\n');
                case 'divider':
                    return '---';
                case 'callout':
                    return '> ' + (block.meta.emoji || '\uD83D\uDCA1') + ' ' + content;
                case 'toggle':
                    return '**' + htmlToMd(block.meta.summary || 'Toggle') + '**\n\n' + content;
                case 'image':
                    return `![${block.meta.alt || ''}](${block.meta.url || ''})`;
                case 'regular':
                case 'paragraph':
                default:
                    return content;
            }
        }).join('\n\n');
    }

    // ═══════════════════════════════════════════════
    // Public API
    // ═══════════════════════════════════════════════

    /**
     * Returns a control object for programmatic interaction.
     */
    getControl() {
        const self = this;
        return {
            /** Get all blocks as data array */
            getBlocks: () => self.#blocks.map(b => ({
                id: b.id, type: b.type, content: b.content, meta: { ...b.meta },
            })),

            /** Replace all blocks */
            setBlocks: (blocks) => {
                // Clear existing
                self.#blocks.forEach(b => {
                    const el = self.#blockElements.get(b.id);
                    if (el) {
                        self.#virtualizer?.unobserveWrapper(el);
                        el[0].remove();
                    }
                });
                self.#blocks = [];
                self.#blockElements.clear();

                self.#bulkLoading = true;
                blocks.forEach(b => self.#addBlock(b.type, null, b.content, b.meta, b.id || null));
                self.#bulkLoading = false;
                if (!self.#blocks.length) self.#addBlock('paragraph');
                self.#virtualizer?.attach();
                self.#resetOpTracking();
            },

            /** Export as Markdown */
            getMarkdown: () => self.#exportMarkdown(),

            /** Import Markdown */
            setMarkdown: async (md) => {
                // Clear existing
                self.#blocks.forEach(b => {
                    const el = self.#blockElements.get(b.id);
                    if (el) {
                        self.#virtualizer?.unobserveWrapper(el);
                        el[0].remove();
                    }
                });
                self.#blocks = [];
                self.#blockElements.clear();

                self.#bulkLoading = true;
                await self.#importMarkdown(md);
                self.#bulkLoading = false;
                if (!self.#blocks.length) self.#addBlock('paragraph');
                self.#virtualizer?.attach();
                self.#resetOpTracking();
            },

            /** Get rendered HTML */
            getHtml: async () => {
                const MarkdownEditor = await getMarkdownEditor();
                return MarkdownEditor.parse(self.#exportMarkdown());
            },

            /** Add a block programmatically */
            addBlock: (type, afterId, content, meta) => {
                const block = self.#addBlock(type, afterId || null, content, meta);
                return { id: block.id, type: block.type };
            },

            /** Remove a block */
            removeBlock: (id) => self.#removeBlock(id),

            /** Move a block */
            moveBlock: (id, newIndex) => self.#moveBlock(id, newIndex),

            /**
             * Return the reconciled delta of user edits since the last
             * ``clearPendingOps()`` — see ``#computePendingOps`` for the
             * exact shape. Hosts forward this to the server's
             * ``commit_delta`` endpoint instead of re-sending
             * ``blocks_json`` (saves the 1 MB round-trip on docs that
             * only nudged a few blocks).
             *
             * The returned array is a fresh copy; callers can mutate it
             * freely.
             *
             * @returns {Array<Object>}
             */
            getPendingOps: () => self.#computePendingOps(),

            /**
             * Mark the editor as clean — the current block list becomes
             * the new baseline for the next delta. Call this **after** a
             * successful commit / delta flush; calling it before the
             * server acknowledges would silently drop edits on network
             * failure.
             */
            clearPendingOps: () => self.#resetOpTracking(),

            /**
             * Fast path — is there anything to flush? Tracks both the
             * structural op log AND a content-vs-snapshot diff, so a
             * single keystroke that went through the plain ``input``
             * handler still shows up here without needing to walk the
             * full op list.
             *
             * @returns {boolean}
             */
            hasPendingOps: () => {
                if (self.#pendingOps.length > 0) return true;
                for (const b of self.#blocks) {
                    const snap = self.#contentSnapshot.get(b.id);
                    if (snap === undefined) return true; // unseen → treat as dirty
                    if (snap !== b.content) return true;
                }
                return false;
            },

            /**
             * Return the set of block ids that are dirty (either in the
             * structural op log or have a content drift vs the
             * snapshot). Hosts use this to gate per-block auto-commit:
             * an AI call against a block that isn't in this set doesn't
             * need to commit at all.
             *
             * @returns {Set<string>}
             */
            getDirtyBlockIds: () => {
                const ids = new Set();
                for (const o of self.#pendingOps) {
                    if (o.block_id) ids.add(o.block_id);
                }
                for (const b of self.#blocks) {
                    const snap = self.#contentSnapshot.get(b.id);
                    if (snap === undefined || snap !== b.content) ids.add(b.id);
                }
                return ids;
            },

            /** Focus a block */
            focus: (id) => {
                if (id) {
                    self.#focusBlock(id);
                } else if (self.#blocks.length) {
                    self.#focusBlock(self.#blocks[0].id, 'start');
                }
            },

            /**
             * Scroll a block into view. Materializes the block first if
             * the virtualizer had unmounted it, so its real bounding box
             * is correct before scrolling.
             */
            scrollToBlock: (id, scrollOpts = { behavior: 'smooth', block: 'center' }) => {
                self.#virtualizer?.ensureMaterialized(id);
                const wrapper = self.#blockElements.get(id);
                const el = wrapper && wrapper[0];
                if (el && typeof el.scrollIntoView === 'function') el.scrollIntoView(scrollOpts);
            },

            /**
             * Virtualization status — for diagnostics and tests. Reports
             * whether the virtualizer is currently active (block count
             * past threshold), how many blocks are mounted vs total, and
             * the resolved config. `null` if disabled at construction.
             */
            get virtualization() {
                if (!self.#virtualizer) return null;
                return {
                    enabled: self.#virtualizer.config.enabled,
                    active: self.#virtualizer.isActive(),
                    materialized: self.#virtualizer.materializedCount,
                    observed: self.#virtualizer.observedCount,
                    total: self.#blocks.length,
                    config: self.#virtualizer.config,
                };
            },

            /**
             * Force-materialize every block — useful if a host needs to
             * snapshot the rendered DOM (print, export-to-HTML, etc.).
             */
            materializeAll: () => {
                if (!self.#virtualizer) return;
                self.#blocks.forEach(b => self.#virtualizer.ensureMaterialized(b.id));
            },

            /** Get the title */
            get title() { return self.#titleEl?.text() || ''; },

            /** Set the title */
            set title(val) { if (self.#titleEl) self.#titleEl.text(val); },

            /** Get block count */
            get blockCount() { return self.#blocks.length; },
            get label()       { return self.#container[0].getAttribute('aria-label'); },
            set label(v)      { v ? self.#container[0].setAttribute('aria-label', v) : self.#container[0].removeAttribute('aria-label'); },
            get labelledby()  { return self.#container[0].getAttribute('aria-labelledby'); },
            set labelledby(v) { v ? self.#container[0].setAttribute('aria-labelledby', v) : self.#container[0].removeAttribute('aria-labelledby'); },
            get describedby() { return self.#container[0].getAttribute('aria-describedby'); },
            set describedby(v){ v ? self.#container[0].setAttribute('aria-describedby', v) : self.#container[0].removeAttribute('aria-describedby'); },
            get element() { return self.#container[0]; },
            get destroyed() { return self.#destroyed; },

            /**
             * Install a plugin after construction. Accepts the same shape as
             * `config.plugins[*]` (function or `{ name, init, destroy }`).
             * Returns a disposer that unregisters everything the plugin
             * registered and calls its `destroy()` (if any).
             */
            installPlugin: (plugin) => {
                if (!self.#pluginHost) return () => {};
                return self.#pluginHost.installPlugin(plugin) || (() => {});
            },

            /**
             * Subscribe to plugin events (`ai:start`, `ai:done`, `ai:diff`,
             * `ai:error`, `change`, `select`, `block:add|remove|move`, …).
             * The handler receives the event *payload* (i.e. ``event.detail``),
             * not the raw ``CustomEvent``, for ergonomic reasons. Returns an
             * unsubscribe function. See
             * [plugin-api.md](../../docs/components/BlockEditor/plugin-api.md).
             *
             * @param {string} name
             * @param {(detail:any)=>void} handler
             * @returns {() => void}
             */
            on: (name, handler) => {
                if (!self.#pluginHost || typeof handler !== 'function') return () => {};
                const wrapped = (ev) => {
                    try { handler(ev && ev.detail !== undefined ? ev.detail : ev); }
                    catch (err) { console.error(`[BlockEditor] handler for "${name}" threw`, err); }
                };
                // Stash the wrapper on the original handler so `.off()` can find it.
                const key = '__be_wrapped_' + name;
                handler[key] = wrapped;
                self.#pluginHost.on(name, wrapped);
                return () => {
                    try { self.#pluginHost?.off(name, wrapped); } catch (_) { /* ignore */ }
                    try { delete handler[key]; } catch (_) { /* ignore */ }
                };
            },

            /** Remove a handler registered via `on()`. */
            off: (name, handler) => {
                if (!self.#pluginHost || typeof handler !== 'function') return;
                const wrapped = handler['__be_wrapped_' + name];
                try { self.#pluginHost.off(name, wrapped || handler); } catch (_) { /* ignore */ }
            },

            /**
             * Emit a plugin event. Host apps normally only need `on()`, but
             * the emit side is exposed so external controllers (e.g. a
             * sidebar that drives the editor) can talk to plugins too.
             */
            emit: (name, detail) => {
                self.#pluginHost?.emit(name, detail);
            },
        };
    }

    /**
     * Destroy the editor and clean up.
     */
    destroy() {
        if (this.#destroyed) return;
        this.#destroyed = true;
        this.#eventAC?.abort();

        // Tear down virtualizer first so its IntersectionObserver doesn't
        // fire materialize() against blocks we're about to delete.
        try { this.#virtualizer?.destroy(); } catch (e) { console.error('[BlockEditor] virtualizer destroy:', e); }
        this.#virtualizer = null;

        // Destroy plugin instances (user plugins get their destroy() called).
        try { this.#pluginHost?.destroy(); } catch (e) { console.error('[BlockEditor] plugin host destroy:', e); }
        this.#pluginHost = null;

        // Destroy all lite MarkdownEditor instances
        this.#liteEditors.forEach(editor => editor.destroy());
        this.#liteEditors.clear();

        this.#container[0].remove();
    }
};

export default BlockEditor;
